import { lazy } from "react";

const Header = lazy(() =>
  wait(3000).then(() => import("../components/Header.jsx"))
);
const Profile = lazy(() =>
  wait(3000).then(() => import("../components/Profile.jsx"))
);
const About = lazy(() =>
  wait(3000).then(() => import("../components/About.jsx"))
);
const Linked = lazy(() =>
  wait(3000).then(() => import("../components/Linked.jsx"))
);
const WaButton = lazy(() =>
  wait(3000).then(() => import("../components/WaButton.jsx"))
);

const Home = ({ handleThemeSwitch, theme }) => {
  return (
    <div className="w-full flex flex-col justify-center items-center pb-5">
      <div className="w-[90%] max-w-[720px]">
        <Header handleThemeSwitch={handleThemeSwitch} theme={theme} />
        <Profile />
        <About />
        <Linked />
        <WaButton />
      </div>
    </div>
  );
};

const wait = (time) => {
  return new Promise((resolve) => {
    setTimeout(resolve, time);
  });
};

export default Home;
